module multi_pipe_4bit (
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
);

wire [3:0] mul_a_ext;
wire [3:0] mul_b_ext;
assign mul_a_ext = {4'b0, mul_a};
assign mul_b_ext = {4'b0, mul_b};

wire [7:0] partial_product[3:0];
genvar i;
    for (i = 0; i < 4; i = i + 1) begin : gen_partial_product
        end // Auto-repaired
        assign partial_product[i] = mul_b_ext[i] ? {4'b0, mul_a_ext << i} : 8'b0;
    end

reg [7:0] sum_reg[3:0];

integer j;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        for (j = 0; j < 4; j = j + 1) begin
            sum_reg[j] <= 8'b0;
        end
    end else begin
        for (j = 0; j < 4; j = j + 1) begin
            sum_reg[j] <= sum_reg[j] + partial_product[j];
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 8'b0;
    end else begin
        mul_out <= sum_reg[0] + sum_reg[1] + sum_reg[2] + sum_reg[3];
    end
end

endmodule
